from dataclasses import dataclass
from typing import Dict, List, Optional

@dataclass
class ServerConfig:
    host: str
    port: int
    workers: int
    timeout: int  # seconds
    max_connections: int

@dataclass
class DatabaseConfig:
    url: str
    pool_size: int
    max_overflow: int
    echo: bool

@dataclass
class CacheConfig:
    backend: str  # "redis" or "memory"
    ttl: int  # seconds
    max_size: int  # entries
    prefix: str

@dataclass
class AppConfig:
    server: ServerConfig
    database: DatabaseConfig
    cache: CacheConfig
    debug: bool

def validate_config(config: AppConfig) -> List[str]:
    """Returns list of validation errors. Empty list = valid."""
    errors = []

    # Server constraints
    if config.server.port < 1024 or config.server.port > 65535:
        errors.append("port must be 1024-65535")
    if config.server.workers < 1 or config.server.workers > 32:
        errors.append("workers must be 1-32")
    if config.server.timeout < 5 or config.server.timeout > 300:
        errors.append("timeout must be 5-300")
    if config.server.max_connections < config.server.workers * 2:
        errors.append("max_connections must be >= workers * 2")

    # Database constraints
    if config.database.pool_size < 1 or config.database.pool_size > 50:
        errors.append("pool_size must be 1-50")
    if config.database.max_overflow < 0 or config.database.max_overflow > config.database.pool_size:
        errors.append("max_overflow must be 0 to pool_size")
    if config.database.pool_size > config.server.max_connections // 2:
        errors.append("pool_size must be <= max_connections // 2")

    # Cache constraints
    if config.cache.backend not in ("redis", "memory"):
        errors.append("cache backend must be redis or memory")
    if config.cache.ttl < 1 or config.cache.ttl > 86400:
        errors.append("cache ttl must be 1-86400")
    if config.cache.max_size < 100 or config.cache.max_size > 100000:
        errors.append("cache max_size must be 100-100000")
    if config.cache.backend == "memory" and config.cache.max_size > 10000:
        errors.append("memory cache max_size must be <= 10000")

    # Cross-cutting constraints
    if config.debug and config.server.workers > 1:
        errors.append("debug mode requires single worker")
    if config.debug and not config.database.echo:
        errors.append("debug mode requires database echo")
    if not config.debug and config.database.echo:
        errors.append("production mode must not echo queries")
    if config.cache.backend == "redis" and config.server.timeout < 10:
        errors.append("redis cache requires timeout >= 10")

    return errors
